def validate_identifier(identifier: str) -> bool:
    return bool(re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', identifier))

def validate_operator(operator: str) -> bool:
    allowed_operators = ['=', '!=', '>', '<', '>=', '<=', 'LIKE', 'ILIKE', 'IN', 'NOT IN', 'IS NULL', 'IS NOT NULL']
    return operator.upper() in allowed_operators

def error_handler(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        try:
            return f(*args, **kwargs)
        except psycopg2.Error as e:
            return jsonify({'error': 'Database error', 'message': str(e)}), 500
        except ValueError as e:
            return jsonify({'error': 'Validation error', 'message': str(e)}), 400
        except Exception as e:
            return jsonify({'error': 'Internal error', 'message': str(e)}), 500
    return decorated_function

def build_where_clause(filters: List[Dict[str, Any]]):
    conditions = []
    params = []
    
    for f in filters:
        column = f.get('column')
        operator = f.get('operator', '=').upper()
        value = f.get('value')
        
        if not column or not validate_identifier(column):
            raise ValueError(f'Invalid column name: {column}')
        
        if not validate_operator(operator):
            raise ValueError(f'Invalid operator: {operator}')
        
        if operator in ['IS NULL', 'IS NOT NULL']:
            conditions.append(sql.SQL('{} {}').format(
                sql.Identifier(column),
                sql.SQL(operator)
            ))
        elif operator in ['IN', 'NOT IN']:
            if not isinstance(value, list):
                raise ValueError(f'Value for {operator} must be a list')
            placeholders = sql.SQL(',').join([sql.Placeholder()] * len(value))
            conditions.append(sql.SQL('{} {} ({})').format(
                sql.Identifier(column),
                sql.SQL(operator),
                placeholders
            ))
            params.extend(value)
        else:
            conditions.append(sql.SQL('{} {} {}').format(
                sql.Identifier(column),
                sql.SQL(operator),
                sql.Placeholder()
            ))
            params.append(value)
    
    return conditions, params

def build_order_clause(order_by: List[Dict[str, str]]):
    order_clauses = []
    
    for order in order_by:
        column = order.get('column')
        direction = order.get('direction', 'ASC').upper()
        
        if not column or not validate_identifier(column):
            raise ValueError(f'Invalid column name: {column}')
        
        if direction not in ['ASC', 'DESC']:
            raise ValueError(f'Invalid order direction: {direction}')
        
        order_clauses.append(sql.SQL('{} {}').format(
            sql.Identifier(column),
            sql.SQL(direction)
        ))
    
    return order_clauses

