@error_handler
def dynamic_query():
    data = request.get_json()
    
    table_name = data.get('table')
    columns = data.get('columns', ['*'])
    filters = data.get('filters', [])
    order_by = data.get('order_by', [])
    limit = data.get('limit', 100)
    offset = data.get('offset', 0)
    
    if not table_name:
        return jsonify({'error': 'Table name is required'}), 400
    
    if table_name not in ALLOWED_TABLES:
        return jsonify({'error': f'Table {table_name} is not allowed'}), 403
    
    if not validate_identifier(table_name):
        return jsonify({'error': 'Invalid table name'}), 400
    
    if limit > MAX_LIMIT:
        limit = MAX_LIMIT
    
    if columns != ['*']:
        for col in columns:
            if not validate_identifier(col):
                return jsonify({'error': f'Invalid column name: {col}'}), 400
    
    query_parts = []
    params = []
    
    if columns == ['*']:
        select_clause = sql.SQL('SELECT * FROM {}').format(sql.Identifier(table_name))
    else:
        column_identifiers = [sql.Identifier(col) for col in columns]
        select_clause = sql.SQL('SELECT {} FROM {}').format(
            sql.SQL(', ').join(column_identifiers),
            sql.Identifier(table_name)
        )
    
    query_parts.append(select_clause)
    
    if filters:
        conditions, filter_params = build_where_clause(filters)
        where_clause = sql.SQL(' WHERE {}').format(
            sql.SQL(' AND ').join(conditions)
        )
        query_parts.append(where_clause)
        params.extend(filter_params)
    
    if order_by:
        order_clauses = build_order_clause(order_by)
        order_clause = sql.SQL(' ORDER BY {}').format(
            sql.SQL(', ').join(order_clauses)
        )
        query_parts.append(order_clause)
    
    query_parts.append(sql.SQL(' LIMIT {} OFFSET {}').format(
        sql.Placeholder(),
        sql.Placeholder()
    ))
    params.extend([limit, offset])
    
    final_query = sql.SQL('').join(query_parts)
    
    conn = get_db_connection()
    try:
        with conn.cursor(cursor_factory=extras.RealDictCursor) as cursor:
            cursor.execute(final_query, params)
            results = cursor.fetchall()
            
            count_query = sql.SQL('SELECT COUNT(*) FROM {}').format(
                sql.Identifier(table_name)
            )
            
            if filters:
                conditions, filter_params = build_where_clause(filters)
                count_query = sql.SQL('{} WHERE {}').format(
                    count_query,
                    sql.SQL(' AND ').join(conditions)
                )
                cursor.execute(count_query, filter_params)
            else:
                cursor.execute(count_query)
            
            total_count = cursor.fetchone()['count']
            
            return jsonify({
                'data': results,
                'meta': {
                    'total': total_count,
                    'limit': limit,
                    'offset': offset,
                    'count': len(results)
                }
            })
    finally:
        conn.close()

