@error_handler
def aggregate_query():
    data = request.get_json()
    
    table_name = data.get('table')
    aggregations = data.get('aggregations', [])
    group_by = data.get('group_by', [])
    filters = data.get('filters', [])
    having = data.get('having', [])
    
    if not table_name:
        return jsonify({'error': 'Table name is required'}), 400
    
    if table_name not in ALLOWED_TABLES:
        return jsonify({'error': f'Table {table_name} is not allowed'}), 403
    
    if not validate_identifier(table_name):
        return jsonify({'error': 'Invalid table name'}), 400
    
    if not aggregations:
        return jsonify({'error': 'Aggregations are required'}), 400
    
    allowed_agg_functions = ['COUNT', 'SUM', 'AVG', 'MIN', 'MAX']
    agg_clauses = []
    
    for agg in aggregations:
        func = agg.get('function', '').upper()
        column = agg.get('column', '*')
        alias = agg.get('alias')
        
        if func not in allowed_agg_functions:
            return jsonify({'error': f'Invalid aggregation function: {func}'}), 400
        
        if column != '*' and not validate_identifier(column):
            return jsonify({'error': f'Invalid column name: {column}'}), 400
        
        if alias and not validate_identifier(alias):
            return jsonify({'error': f'Invalid alias: {alias}'}), 400
        
        if column == '*':
            agg_sql = sql.SQL('{}(*)').format(sql.SQL(func))
        else:
            agg_sql = sql.SQL('{}({})').format(sql.SQL(func), sql.Identifier(column))
        
        if alias:
            agg_sql = sql.SQL('{} AS {}').format(agg_sql, sql.Identifier(alias))
        
        agg_clauses.append(agg_sql)
    
    select_parts = []
    
    for col in group_by:
        if not validate_identifier(col):
            return jsonify({'error': f'Invalid group by column: {col}'}), 400
        select_parts.append(sql.Identifier(col))
    
    select_parts.extend(agg_clauses)
    
    query_parts = []
    params = []
    
    select_clause = sql.SQL('SELECT {} FROM {}').format(
        sql.SQL(', ').join(select_parts),
        sql.Identifier(table_name)
    )
    query_parts.append(select_clause)
    
    if filters:
        conditions, filter_params = build_where_clause(filters)
        where_clause = sql.SQL(' WHERE {}').format(
            sql.SQL(' AND ').join(conditions)
        )
        query_parts.append(where_clause)
        params.extend(filter_params)
    
    if group_by:
        group_identifiers = [sql.Identifier(col) for col in group_by]
        group_clause = sql.SQL(' GROUP BY {}').format(
            sql.SQL(', ').join(group_identifiers)
        )
        query_parts.append(group_clause)
    
    if having:
        having_conditions, having_params = build_where_clause(having)
        having_clause = sql.SQL(' HAVING {}').format(
            sql.SQL(' AND ').join(having_conditions)
        )
        query_parts.append(having_clause)
        params.extend(having_params)
    
    final_query = sql.SQL('').join(query_parts)
    
    conn = get_db_connection()
    try:
        with conn.cursor(cursor_factory=extras.RealDictCursor) as cursor:
            cursor.execute(final_query, params)
            results = cursor.fetchall()
            
            return jsonify({
                'data': results,
                'meta': {
                    'count': len(results)
                }
            })
    finally:
        conn.close()

