@app.route('/api/schema/<table_name>', methods=['GET'])
@error_handler
def get_table_schema(table_name):
    if table_name not in ALLOWED_TABLES:
        return jsonify({'error': f'Table {table_name} is not allowed'}), 403
    
    if not validate_identifier(table_name):
        return jsonify({'error': 'Invalid table name'}), 400
    
    conn = get_db_connection()
    try:
        with conn.cursor(cursor_factory=extras.RealDictCursor) as cursor:
            query = sql.SQL("""
                SELECT 
                    column_name,
                    data_type,
                    is_nullable,
                    column_default
                FROM information_schema.columns
                WHERE table_name = %s
                ORDER BY ordinal_position
            """)
            cursor.execute(query, [table_name])
            columns = cursor.fetchall()
            
            return jsonify({
                'table': table_name,
                'columns': columns
            })
    finally:
        conn.close()

@app.route('/api/join', methods=['POST'])
@error_handler
def join_query():
    data = request.get_json()
    
    base_table = data.get('base_table')
    joins = data.get('joins', [])
    columns = data.get('columns', ['*'])
    filters = data.get('filters', [])
    limit = data.get('limit', 100)
    offset = data.get('offset', 0)
    
    if not base_table:
        return jsonify({'error': 'Base table is required'}), 400
    
    if base_table not in ALLOWED_TABLES:
        return jsonify({'error': f'Table {base_table} is not allowed'}), 403
    
    if not validate_identifier(base_table):
        return jsonify({'error': 'Invalid table name'}), 400
    
    if limit > MAX_LIMIT:
        limit = MAX_LIMIT
    
    query_parts = []
    params = []
    
    if columns == ['*']:
        select_clause = sql.SQL('SELECT * FROM {}').format(sql.Identifier(base_table))
    else:
        column_parts = []
        for col in columns:
            if '.' in col:
                table_part, col_part = col.split('.', 1)
                if not validate_identifier(table_part) or not validate_identifier(col_part):
                    return jsonify({'error': f'Invalid column: {col}'}), 400
                column_parts.append(sql.SQL('{}.{}').format(
                    sql.Identifier(table_part),
                    sql.Identifier(col_part)
                ))
            else:
                if not validate_identifier(col):
                    return jsonify({'error': f'Invalid column: {col}'}), 400
                column_parts.append(sql.Identifier(col))
        
        select_clause = sql.SQL('SELECT {} FROM {}').format(
            sql.SQL(', ').join(column_parts),
            sql.Identifier(base_table)
        )
    
    query_parts.append(select_clause)
    
    for join in joins:
        join_type = join.get('type', 'INNER').upper()
        join_table = join.get('table')
        on_conditions = join.get('on', [])
        
        if join_type not in ['INNER', 'LEFT', 'RIGHT', 'FULL']:
            return jsonify({'error': f'Invalid join type: {join_type}'}), 400
        
        if join_table not in ALLOWED_TABLES:
            return jsonify({'error': f'Join table {join_table} is not allowed'}), 403
        
        if not validate_identifier(join_table):
            return jsonify({'error': f'Invalid join table: {join_table}'}), 400
        
        join_clause = sql.SQL(' {} JOIN {}').format(
            sql.SQL(join_type),
            sql.Identifier(join_table)
        )
        
        if on_conditions:
            on_parts = []
            for condition in on_conditions:
                left_col = condition.get('left')
                right_col = condition.get('right')
                
                if '.' not in left_col or '.' not in right_col:
                    return jsonify({'error': 'Join conditions must use table.column format'}), 400
                
                left_table, left_column = left_col.split('.', 1)
                right_table, right_column = right_col.split('.', 1)
                
                if not all([validate_identifier(x) for x in [left_table, left_column, right_table, right_column]]):
                    return jsonify({'error': 'Invalid join condition'}), 400
                
                on_parts.append(sql.SQL('{}.{} = {}.{}').format(
                    sql.Identifier(left_table),
                    sql.Identifier(left_column),
                    sql.Identifier(right_table),
                    sql.Identifier(right_column)
                ))
            
            join_clause = sql.SQL('{} ON {}').format(
                join_clause,
                sql.SQL(' AND ').join(on_parts)
            )
        
        query_parts.append(join_clause)
    
    if filters:
        conditions, filter_params = build_where_clause(filters)
        where_clause = sql.SQL(' WHERE {}').format(
            sql.SQL(' AND ').join(conditions)
        )
        query_parts.append(where_clause)
        params.extend(filter_params)
    
    query_parts.append(sql.SQL(' LIMIT {} OFFSET {}').format(
        sql.Placeholder(),
        sql.Placeholder()
    ))
    params.extend([limit, offset])
    
    final_query = sql.SQL('').join(query_parts)
    
    conn = get_db_connection()
    try:
        with conn.cursor(cursor_factory=extras.RealDictCursor) as cursor:
            cursor.execute(final_query, params)
            results = cursor.fetchall()
            
            return jsonify({
                'data': results,
                'meta': {
                    'limit': limit,
                    'offset': offset,
                    'count': len(results)
                }
            })
    finally:
        conn.close()

